mapper.update:
UPDATE im_conversation_user
SET deleted = 0
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE im_conversation_user
SET unread_count = unread_count + 1,
    deleted = 0
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE im_conversation_user cu
SET cu.last_read_seq = GREATEST(cu.last_read_seq, #{lastReadSeq}),
    cu.unread_count = (
        SELECT COUNT(1)
        FROM im_message m
        WHERE m.conversation_id = #{conversationId}
          AND m.seq_no > GREATEST(cu.last_read_seq, #{lastReadSeq})
          AND m.from_user_id != #{userId}
    )
WHERE cu.conversation_id = #{conversationId}
  AND cu.user_id = #{userId}
